import requests
from urllib.parse import urlparse

def lambda_handler(event, context):
    viewer_request = event['Records'][0]['cf']['request']
    
    # Fetch additional data from URLs specified in request headers
    enrich_urls = viewer_request.get('headers', {}).get('x-enrich-url', [])
    enriched_data = {}
    
    for url in enrich_urls:
        try:
            response = requests.get(url)
            if response.status_code == 200:
                enriched_data[url] = response.json()  # Assuming the data is JSON
            else:
                enriched_data[url] = {'error': 'Failed to fetch data'}
        except Exception as e:
            enriched_data[url] = {'error': str(e)}
    
    # Add enriched data to viewer request headers
    for url, data in enriched_data.items():
        viewer_request['headers']['x-enriched-data'] = [{'key': 'X-Enriched-Data', 'value': str(data)}]
    
    return viewer_request